  '{"document_kind":"tour_product_full_page_v1","schema_version":1,"slug":"jeju-grand-highlights-loop","locale":"zh-CN","product_id":"jeju-grand-highlights-loop","seo":{"pageTitle":"济州岛汉拿山・大浦柱状节理带・正房瀑布・城山日出峰小团一日游 | AtoC Korea","metaDescription":"专为时间有限、想一天高效打卡济州代表景点的旅行者设计。从汉拿山到大浦柱状节理带、正房瀑布，再到城山日出峰，这条高密度小团路线将济州最具标志性的自然风光浓缩进一天。"},"catalog_card":{"slug":"jeju-grand-highlights-loop","title":"济州环岛精华一日小团","subtitle":"从汉拿山到城山日出峰，一天高效串联济州代表级风景。","region":"济州环岛路线","duration":"9–9.5小时","stopsCount":5,"rating":0,"reviewCount":0,"badges":["一日游首选","高密度精华路线"],"heroImage":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1920&q=80","thumbnail":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=600&q=80","priceLabel":"US$78/人起","shortCardDescription":"适合停留时间有限的旅客，一天内高效串联汉拿山、济州南海岸与城山日出峰等经典地标。"},"headlineLine1":"济州环岛精华","headlineLine2":"一日小团","price":{"amountLabel":"78","currency":"USD","per":"人"},"hero":{"imageUrl":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1920&q=80","imagePosition":"center 35%","tagline":"为时间有限的旅客打造，这条高密度路线可在一天内高效游览汉拿山、壮观的南海岸风景、瀑布与城山日出峰。","pills":["一日游首选","精品小团一日游","济州经典地标"],"meta":{"duration":"9–9.5小时","region":"济州环岛路线","stops":"5站","rating":0,"ratingStars":0}},"subnavItems":[{"id":"overview","label":"行程概览"},{"id":"itinerary","label":"详细行程"},{"id":"details","label":"路线亮点"},{"id":"faq","label":"常见问题"},{"id":"reviews","label":"用户评价"}],"glanceItems":[{"icon":"camera","label":"出片指数","value":"高"},{"icon":"mountain","label":"景观密度","value":"非常高"},{"icon":"footprints","label":"步行强度","value":"中等偏高"},{"icon":"cloud-rain","label":"雨天适配度","value":"中等"},{"icon":"users","label":"家庭友好度","value":"中等"},{"icon":"gauge","label":"整体节奏","value":"偏快"}],"galleryItems":[{"id":1,"type":"photo","src":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1200&q=80","location":"整体路线","atmosphere":"一天看尽济州代表性自然风光","alt":"济州精华一日游整体氛围"},{"id":2,"type":"photo","src":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800&q=80","location":"汉拿山开场站","atmosphere":"高海拔地带清爽通透的山间空气","alt":"汉拿山御乘生岳步道氛围"},{"id":3,"type":"photo","src":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=800&q=80","location":"柱状节理海岸","atmosphere":"海浪与绝壁形成鲜明对比","alt":"济州大浦柱状节理带海岸景观"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&q=80","location":"海边瀑布","atmosphere":"下午路线中的风景层次切换","alt":"正房瀑布海岸风光"},{"id":5,"type":"photo","src":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&q=80","location":"火山口收官","atmosphere":"具有标志性的收尾视野，冲击感十足","alt":"城山日出峰火山口与海岸线"}],"itineraryStops":[{"number":1,"time":"09:30","duration":"70分钟","name":"汉拿山御乘生岳","category":"汉拿山山麓步道","description":"行程从汉拿山清爽通透的高地空气开始。御乘生岳将森林步道、火山坡面与观景点串联在一起，从第一站起就把整天的气势拉满。","image":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800&q=80","highlights":["汉拿山中相对容易接近、辨识度很高的代表性观景点之一","以森林步道与山间空气开启一天，开场体验非常舒服","相比直接从市区前往海边，更能让人立刻感受到济州的地形特色","即使时间有限，这一站也足以留下鲜明第一印象"],"timeUsed":["到达后进行步道说明与行走节奏确认","主要上坡步行前往观景点","短暂拍照与休息后下行"],"whyOnRoute":"从这里开始，能先建立汉拿山的高度感、能量感与济州山地印象，再自然衔接到南海岸。","visitBasics":{"hours":"05:00起开放，可能受季节性规定影响","closed":"恶劣天气时可能临时限制进入","admission":"免费","walking":"中等坡度"},"convenience":{"restroom":"步道入口处设有洗手间","parking":"可停车"},"smartNotes":{"photo":"天气晴朗时，拍摄山脊与远景的大场景照片，通常会比近景人像更出效果。","facilities":"基础设施主要集中在入口区域。","tip":"雨后或天气偏冷时，这一站对防滑与保暖的要求会比其他景点更明显。"}},{"number":2,"time":"11:15","duration":"40分钟","name":"大浦柱状节理带","category":"玄武岩海岸","description":"离开汉拿山后，行程氛围在南海岸迅速切换。海浪、玄武岩柱与海边绝壁形成强烈对比，在午餐前就把整天的视觉张力明显拉高。","image":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=800&q=80","highlights":["沿海岸线展开的六角形玄武岩柱景观","接续汉拿山段之后，海蚀崖海岸形成鲜明反差","停留时间不长，但视觉冲击力很强，效率很高","是济州南部极具代表性的拍照点之一"],"timeUsed":["入口处简短讲解","步行前往主要海岸观景点","拍照后返回集合点"],"whyOnRoute":"这一站能高效呈现济州南海岸的典型风貌，同时不会让上午再增加一段过长步行。","visitBasics":{"hours":"09:00–18:00（最晚入场17:40）","closed":"全年开放","admission":"成人KRW 2,000 / 儿童及青少年KRW 1,000","walking":"轻松至中等"},"convenience":{"restroom":"入口区域","parking":"可停车（收费停车场）"},"smartNotes":{"photo":"海浪方向、水雾与侧光会快速改变画面氛围，这里特别适合拍大范围海岸构图。","facilities":"入口区域配套完善，前往观景点的步道整体也较好走。","tip":"即使是晴天，海边体感通常也会比济州内陆更冷、更有风。"}},{"number":3,"time":"12:15","duration":"60分钟","name":"午餐","category":"午餐站","description":"这不只是行程中的休息时间，也是为下半天正房瀑布与城山日出峰保留体力的关键补给点。","image":"https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=800&q=80","highlights":["在高节奏路线中明确划出的体力恢复节点","为继续向东移动前补足状态","对不同年龄段、偏爱活动型观光的旅客都很实用","有助于避免整天行程显得过于压缩"],"timeUsed":["到店与入座","用餐与短暂休息","整理后出发前往下午路线"],"whyOnRoute":"把午餐安排在这里，可以让下半天的体验更稳定，不会让整条路线只剩下赶路感。","visitBasics":{"hours":"视餐厅营业时间而定","closed":"依店家情况而异","admission":"如无特别说明，餐费现场自理","walking":"几乎无需步行"},"convenience":{"restroom":"餐厅内","parking":"可停车"},"smartNotes":{"photo":"整天多为风景题材，午餐照片能让行程视觉节奏更丰富。","facilities":"用餐相关设施通常都比较充足。","tip":"这里更适合从容吃完、好好恢复体力，而不是匆忙解决。"}},{"number":4,"time":"13:35","duration":"50分钟","name":"正房瀑布","category":"直落入海的瀑布","description":"午餐后，正房瀑布会为路线带来完全不同的景观质感。石阶、海雾与瀑布直落海边的画面，共同构成济州南部极具辨识度的一幕。","image":"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&q=80","highlights":["瀑布与礁石海岸同框，画面紧凑又有层次","午餐后能明显感受到氛围切换","在前往东部之前，继续维持路线的视觉张力","即使是高密度精华路线，也能带来明显景观变化"],"timeUsed":["到达后确认入口动线","前往瀑布主景区域参观","拍照、短暂休息后返回"],"whyOnRoute":"在前往城山日出峰之前，再次强化一次济州南海岸的印象，让整条路线更完整。","visitBasics":{"hours":"09:00–17:20","closed":"全年开放","admission":"成人KRW 2,000 / 儿童KRW 1,000","walking":"中等，含台阶"},"convenience":{"restroom":"入口区域","parking":"可停车"},"smartNotes":{"photo":"下方岩石区域很适合拍氛围感照片，但落脚点与海水飞沫会让现场体验更有挑战性。","facilities":"基础设施集中在入口附近。","tip":"由于有台阶和岩石路面，现场体感通常会比地图上看起来更费体力一些。"}},{"number":5,"time":"15:25","duration":"70分钟","name":"城山日出峰","category":"火山口收官站","description":"以城山日出峰作为最后一站，会让这条路线的收尾格外鲜明。经历汉拿山、南海岸与正房瀑布之后，在济州最具代表性的地标之一结束一天，整体完成度会非常高。","image":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&q=80","highlights":["以济州代表性地标作为压轴收官","为高密度的一天带来非常明确的视觉回报","可根据团队节奏选择登顶或停留在下方观景区","对第一次来济州、时间有限的旅客尤其有吸引力"],"timeUsed":["到达后讲解路线与步行节奏","登顶主线或下方观景替代方案","拍照、集合后返回济州市区"],"whyOnRoute":"这里是最适合作为全天收官的象征性地点，也让这条路线真正呈现出“济州环岛精华一日游”的完成感。","visitBasics":{"hours":"收费入场时间会因季节调整","closed":"每月第一个周一休息，如遇法定节假日则顺延至次日","admission":"成人KRW 5,000 / 儿童KRW 2,500","walking":"中等至中等偏高，如选择登顶会更费体力"},"convenience":{"restroom":"下方区域及周边设施内","parking":"大型停车场"},"smartNotes":{"photo":"相比只拍山顶，把火山口与海岸线一起纳入广角构图，通常更有成片效果。","facilities":"山脚区域配套较完善。","tip":"人流、天气与团队体力状况，都会影响登顶体验的强度与满意度。"}}],"routeFlowStops":[{"id":"01","name":"御乘生岳","theme":"汉拿山"},{"id":"02","name":"柱状节理带","theme":"海岸绝壁"},{"id":"03","name":"午餐","theme":"补给休整"},{"id":"04","name":"正房瀑布","theme":"瀑布"},{"id":"05","name":"城山日出峰","theme":"火山口"}],"routePhases":[{"label":"上午","range":"1-2","theme":"从汉拿山到南海岸","bgClass":"bg-sky-50/70","textClass":"text-sky-700","dotClass":"bg-sky-500"},{"label":"中午至下午前段","range":"3-4","theme":"午餐与瀑布","bgClass":"bg-amber-50/70","textClass":"text-amber-700","dotClass":"bg-amber-500"},{"label":"收官段","range":"5","theme":"城山日出峰收尾","bgClass":"bg-emerald-50/70","textClass":"text-emerald-700","dotClass":"bg-emerald-500"}],"routeShapeIntro":{"title":"当天行程如何展开","subtitle":"路线从汉拿山出发，穿过济州南海岸，最后在城山日出峰收官。通常08:30–09:00开始接人，约17:40–18:00返回济州市区。"},"whyTourWorks":{"bestFor":["在济州只有一天时间的旅客","早上抵达济州、想高效安排一天行程的旅客","想优先打卡经典地标的旅客","喜欢偏活动型观光节奏的旅客"],"lessIdeal":["偏好慢节奏旅行的旅客","不想走台阶或上坡路段的旅客","携带很小孩子同行的家庭","高度依赖婴儿车出行的团队"],"routeLogicSections":[{"title":"为时间有限的旅客而设计","icon":"clock-3","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"先从汉拿山开始","detail":"以汉拿山开场，能在真正进入跨岛移动前，先建立对济州山地地貌的整体感受。"},{"label":"把南海岸安排在中段","detail":"柱状节理带、午餐与正房瀑布让路线从西向东推进时，依然保持很高的风景密度。"},{"label":"最后以城山日出峰收官","detail":"把城山放在最后，会让整天不只是几个分散区域的拼接，而更像一条完整的济州精华路线。"}]},{"title":"为什么这一天会显得特别充实","icon":"mountain","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"两段更有活动量的步行","detail":"御乘生岳与城山日出峰让这条路线的体力需求，明显高于一般小团一日游。"},{"label":"优先保证风景密度","detail":"这不是慢慢看的放松型路线，而是为想在一天里更扎实感受济州的人设计。"},{"label":"当时间很紧时尤其值得","detail":"如果在济州只有一天，优先集中打卡最具代表性的景点，通常比把节奏放得太松更划算。"}]},{"title":"遇到现场条件变化时","icon":"wind","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"汉拿山入山限制","detail":"御乘生岳可能会受到季节规定或天气管制影响。"},{"label":"海岸露天景点受风影响","detail":"柱状节理带与城山日出峰是两处最容易受到天气影响的海岸景点。"},{"label":"返程时间可能会小幅变动","detail":"路况、团队步行速度与现场拥挤程度，都可能让最终返程时间出现少量浮动。"}]}]},"practicalAccordionItems":[{"id":"pickup","title":"接送与返程时间","preview":"早出发，傍晚返回济州市区","content":["08:30–09:00在济州市区范围内接人","约17:40–18:00返回济州市区","是否可安排机场接人需视当日情况而定","最终集合时间会在出发前一晚确认"]},{"id":"walking","title":"步行与路况说明","preview":"比标准路线更有活动量","content":["这条路线包含两段相对更有活动量的步行。","御乘生岳包含上坡步行与台阶路段。","正房瀑布包含台阶与岩石步道。","如果团队选择登顶，城山日出峰这一段会更费体力。","强烈建议穿着抓地力好的舒适步行鞋。"]},{"id":"weather","title":"天气与临时调整","preview":"通常照常进行，必要时会灵活调整","content":["小雨：通常按原计划出发","大风：柱状节理带或城山日出峰等露天路段可能会缩短停留时间","汉拿山管制：如御乘生岳受限，路线可能调整或替换景点","闭园日：必要时会改用替代景点或调整停留时长"]},{"id":"flight","title":"如果你当天抵达或离开济州","preview":"需要预留充足的晚间缓冲时间","content":["这是一条在一天内高效覆盖济州代表性景点的高密度路线。","当天抵达或离开理论上可以参加，但前提是你的时间安排必须留出足够的晚间余量。","强烈建议选择较晚的航班。","判断时间风险时，请把路况、步行节奏与现场情况一并考虑进去。"]},{"id":"wear","title":"建议穿着与随身物品","preview":"步行鞋、分层穿搭与轻便防风外套","content":["抓地力好的步行鞋","适合山地与海边温差的分层穿搭","轻便防风外套","帽子与防晒用品","饮用水"]},{"id":"included","title":"费用包含 / 不包含","preview":"导游、车辆、接送与门票已含","variant":"included","content":["专业英语导游","小团用车","济州市区酒店接送","全部景点门票","瓶装水","午餐（现场自理）","个人购物消费","导游小费"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"实时天气接入"},"tomorrow":{"temp":"—","label":"每日更新"}},"seasonalVariations":[{"name":"春季","icon":"flower","description":"山间空气尤其清爽，整个岛上的能见度通常也更干净、更通透。","tag":"整体平衡最佳","bgClass":"bg-spring","iconColor":"text-pink-500"},{"name":"夏季","icon":"sun","description":"白天时间最长，海岸线的色彩往往也最鲜明饱和。","tag":"日照时间最长","bgClass":"bg-summer","iconColor":"text-sky-500"},{"name":"秋季","icon":"leaf","description":"晴朗天气较多时，这条环岛路线从头到尾都会显得格外满足。","tag":"能见度最佳","bgClass":"bg-autumn","iconColor":"text-amber-600"},{"name":"冬季","icon":"snow","description":"空气更冷冽清透，山与海之间的对比也会更加鲜明。","tag":"清透利落","bgClass":"bg-winter","iconColor":"text-slate-500"}],"bookingTrustItems":[{"icon":"clock-3","title":"一天尽可能看更多","description":"专为时间有限的旅客设计","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"mountain","title":"聚焦济州代表性地标","description":"从汉拿山一路到城山日出峰","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"精品小团运营","description":"更便于根据路况与现场情况灵活应对","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"预订后","title":"即时确认","detail":"系统会发送包含路线摘要的预订确认信息。"},{"timing":"出发前12小时","title":"行前提醒","detail":"提前分享天气提示与路线调整说明。"},{"timing":"出发前一晚","title":"最终接送通知","detail":"你会收到准确的接送时间与联系方式。"},{"timing":"出发当天早上","title":"当天路线提醒","detail":"如有最新现场变化，会在出发前简要通知。"},{"timing":"行程中","title":"分站讲解支持","detail":"根据需要在每个停靠点提供重点说明。"},{"timing":"行程结束后","title":"行后支持","detail":"如有需要，可继续提供后续协助与补充推荐。"}],"staticQuestions":[{"id":"one-day","question":"如果我在济州只有一天时间，这条路线适合吗？","answer":"适合。这条路线就是为想在一天内高效打卡济州核心地标的旅客设计的，整体节奏会比标准一日游更快。"},{"id":"tiring","question":"这条路线会不会比较累？","answer":"整体上会比一般小团一日游更有活动量，因为有两段更明显的步行路段，而且覆盖范围也更大。"},{"id":"parents","question":"适合带父母一起参加吗？","answer":"主要取决于他们对步行和较快观光节奏的接受度。相比完全放松型观光，这条路线更适合体力较好的成人旅客。"},{"id":"flight","question":"如果我当天到达或离开济州，还能参加吗？","answer":"有可能，但前提是你晚上的时间缓冲必须足够。如果航班时间比较紧张，不建议选择这条路线。"},{"id":"order","question":"当天景点顺序会调整吗？","answer":"会有可能。为了让整天行程更顺畅，景点顺序可能会根据路况、天气与现场人流做小幅调整。"},{"id":"seongsan-last","question":"为什么把城山日出峰安排在最后？","answer":"因为这样收尾更有力。经历汉拿山、南海岸和正房瀑布之后，以城山作结会更有“济州代表线路”的完整感。"},{"id":"summit","question":"城山日出峰一定要登顶吗？","answer":"不一定。是否登顶，以及这一段的执行强度，会根据团队节奏、天气与现场人流情况灵活调整。"}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.","price":{"amountLabel":"78","currency":"USD","per":"人"}},"matching_profile":{"product_type":"small_group","route_type":"fixed_route","region_type":"full_island","region_tags":["jeju_all_around","hallasan_to_seongsan"],"theme_tags":["hallasan","basalt","waterfall","crater","fast_paced","one_day"],"poi_tags":["eoseungsaengak","jusangjeolli","jeongbang","seongsan"],"pace_level":5,"walking_level":4,"scenic_level":5,"photo_level":5,"culture_level":2,"relax_level":2,"first_time_fit":5,"family_fit":2,"senior_fit":2,"couple_fit":4,"active_traveler_fit":5,"one_day_fit":5,"same_day_flight_fit":1,"rain_fit":2,"value_for_money_fit":3,"iconic_landmark_fit":5,"cafe_fit":1,"adult_family_fit":3,"young_kids_fit":2,"senior_active_fit":3,"senior_general_fit":2,"mobility_friendly_fit":2,"stroller_fit":1,"indoor_ratio":28,"weather_sensitivity":4,"local_culture_fit":2,"shopping_fit":1,"storytelling_fit":3,"comfort_level":2,"budget_fit":3,"premium_fit":3,"small_group_fit":5,"private_fit":1,"bus_fit":1,"price_band":"mid","pickup_base":"jeju_city","return_time_band":"17:40-18:15","duration_band":"9.5h","min_recommended_age":10,"hard_constraints":{"avoidIf":["needs_slow_pace","tight_same_day_departure","strict_same_day_flight_schedule"],"notIdealFor":["toddlers","stroller_heavy","very_low_mobility"]},"walking_notes":["Eoseungsaengak includes about 1 hour of uphill trail walking","Jeongbang Waterfall includes a stair section","Seongsan Ilchulbong summit climb is recommended and takes about 55 minutes"],"keywords":["jeju one day tour","jeju full island loop","hallasan","seongsan ilchulbong","jusangjeolli cliff","jeongbang waterfall","jeju grand tour","fast paced jeju tour","jeju highlights","jeju iconic landmarks","jeju day trip","jeju full day highlights","hallasan to seongsan","jeju small group day tour"],"synonym_hints":["full island loop","highlights in one day","busy but iconic","see more in one day","fast highlights route","jeju full day landmarks","one day around jeju","iconic jeju route"],"profile_version":3,"is_active":true},"matching_metadata":{"schema_version":"tour_matching_profile.v1","last_reviewed_at":"2026-04-22","score_rationale":{"pace_level":"A 9–9.5 hour route with five major stops and an optional Seongsan summit section, making this one of the fastest-paced products in the lineup.","walking_level":"Moderate to moderately high due to the uphill Eoseungsaengak section, stairs at Jeongbang, and the recommended Seongsan summit climb.","scenic_level":"Very high, with classic Jeju iconography concentrated into one route: Hallasan, basalt cliffs, waterfall, and volcanic crater scenery.","culture_level":"Low to moderate because the route is centered on geology and nature rather than history, village life, or cultural immersion.","relax_level":"Low, because the fixed route and tight timing prioritize coverage over leisure.","first_time_fit":"An almost textbook highlights set for first-time visitors to Jeju.","family_fit/young_kids_fit/stroller_fit":"Not ideal for toddlers or stroller-heavy groups because of stairs, trails, and the overall pace.","senior_fit/senior_general_fit/mobility_friendly_fit":"General or low-stamina seniors are not the best fit; active seniors may still enjoy it.","same_day_flight_fit":"The 17:40–18:15 return window creates clear risk for tight same-day departure schedules.","rain_fit/indoor_ratio/weather_sensitivity":"Indoor ratio is only 28%, and both coastal and mountain sections are sensitive to poor weather.","local_culture_fit/shopping_fit":"There are no market, village, or shopping-focused stops on this route.","small_group_fit/private_fit/bus_fit":"Built specifically for small-group SUV/van operation, not as a private-only or large-bus product.","price_band/budget_fit/premium_fit":"At US$78, it sits in the mid-price band rather than at either the premium or low-budget extreme.","hard_constraints":"Hard exclusions apply to travelers requesting a slow pace, those with same-day flight pressure, and travelers with toddlers, strollers, or very low mobility."}}}'::jsonb
